<template>
  <div class="container mt-6 mt-md-15 flex-shrink-0 flex-grow-1">
    <div class="row">
      <main class="col-md-7 col-xl-4 mx-auto">
        <h2 class="mb-4">
          <IconTitle title="會員登入" />
        </h2>

        <VeeForm v-slot="{ errors }" class="d-flex flex-column" @submit="login">
          <!-- 帳號 -->
          <div class="mb-4">
            <label for="account" class="form-label">帳號</label>
            <VeeField
              type="text"
              name="account"
              id="account"
              :class="['form-control', errors.account ? 'is-invalid' : '']"
              placeholder="請輸入帳號"
              rules="required"
              label="帳號"
              v-model="form.account"
            />
            <VeeErrorMessage name="account" class="invalid-feedback" />
          </div>

          <!-- 密碼 -->
          <div class="mb-6 mb-md-8">
            <label for="password" class="form-label">密碼（8 ~ 12 碼英數字）</label>

            <div class="d-flex align-items-center">
              <VeeField
                :type="isShowPassword ? 'text' : 'password'"
                name="password"
                id="password"
                :class="['form-control', 'me-3', errors.password ? 'is-invalid' : '']"
                placeholder="請輸入密碼"
                maxlength="12"
                rules="required|password"
                label="密碼"
                v-model="form.password"
              />
              <PwdDisplaySwitch v-model:isShowPassword="isShowPassword" />
            </div>

            <VeeErrorMessage name="password" class="invalid-feedback d-block" />
          </div>

          <!-- 登入 -->
          <button
            class="btn btn-primary py-4 py-md-2 fs-18 fs-md-20 lh-1d444 lh-md-1d45 d-flex justify-content-center align-items-center w-100"
          >
            <span class="me-1">登入</span>
            <i class="icofont-rounded-double-right"></i>
          </button>
        </VeeForm>
      </main>
    </div>
    <!-- row end -->
  </div>
</template>

<script>
import { mapActions } from "pinia";
import { useLoadingStore } from "@/stores";
import { AuthService } from "@/services";
import IconTitle from "@/components/global/IconTitle.vue";
import PwdDisplaySwitch from "@/components/global/PwdDisplaySwitch.vue";

export default {
  data() {
    return {
      isShowPassword: false, // 是否顯示密碼，預設不顯示

      // 表單資料
      form: {
        // TODO test
        account: "test@7tao.com",
        password: "A123456789",
      },
    };
  },

  methods: {
    /** loading 功能 */
    ...mapActions(useLoadingStore, {
      openLoading: "open",
      closeLoading: "close",
    }),

    /**
     * 登入。
     */
    login() {
      // AuthService.loginAndRedirect(this.form.account, this.form.password);
      AuthService.loginAndRedirect();
    },
  },

  components: { IconTitle, PwdDisplaySwitch },
};
</script>
